description:
Use this tool to update a quiz created by the start-quiz tool.  Use this tool to update quiz state in the UI based on the user's voice input (e.g., selecting an option, going to next/previous question, or finishing the quiz).

- When to use: After the user provides an answer or a navigation intent during an active quiz. 

  "quiz_steps": [

    {

      "index": 1,

      "id": "loanAmount",

      "question": "How much loan amount do you need?",

      "options": [

        { "position": 1, "value": "1000-3000", "label": "$1,000 - $3,000" },

        { "position": 2, "value": "3000-5000", "label": "$3,000 - $5,000" },

        { "position": 3, "value": "5000-10000", "label": "$5,000 - $10,000" },

        { "position": 4, "value": "10000+", "label": "$10,000+" }

      ]

    },

    {

      "index": 2,

      "id": "loanPurpose",

      "question": "What is the primary purpose for this loan?",

      "options": [

        { "position": 1, "value": "home_improvement", "label": "Home improvement" },

        { "position": 2, "value": "medical", "label": "Medical expenses" },

        { "position": 3, "value": "education", "label": "Education" },

        { "position": 4, "value": "debt_consolidation", "label": "Debt consolidation" },

        { "position": 5, "value": "other", "label": "Other" }

      ]

    },

    {

      "index": 3,

      "id": "employmentType",

      "question": "What is your current employment status?",

      "options": [

        { "position": 1, "value": "salaried", "label": "Salaried Employee" },

        { "position": 2, "value": "self_employed", "label": "Self-employed / Business" }

      ]

    },

    {

      "index": 4,

      "id": "monthlyIncome",

      "question": "What is your monthly take-home income?",

      "options": [

        { "position": 1, "value": "2500-4000", "label": "$2,500 - $4,000" },

        { "position": 2, "value": "4000-6000", "label": "$4,000 - $6,000" },

        { "position": 3, "value": "6000-10000", "label": "$6,000 - $10,000" },

        { "position": 4, "value": "10000+", "label": "$10,000+" }

      ]

    },

    {

      "index": 5,

      "id": "loanTenure",

      "question": "What loan repayment tenure do you prefer?",

      "options": [

        { "position": 1, "value": "12", "label": "1 Year (Higher EMI, Lower Interest)" },

        { "position": 2, "value": "24", "label": "2 Years (Balanced Option)" },

        { "position": 3, "value": "36", "label": "3 Years (Popular Choice)" },

        { "position": 4, "value": "48", "label": "4 Years (Lower EMI)" },

        { "position": 5, "value": "60", "label": "5 Years (Lowest EMI, Higher Interest)" }

      ]

    }

  ],

  "notes": [

    "Use options[*].value exactly for selected_value (string match).",

    "After selectOption nextQuestion switch is done automatically in 1.5 sec, do not triger nextQuestion after selectOption".

    "For navigation, use question_id=\"current\" with action nextQuestion | prevQuestion | showResults.",

    "Actions: selectOption | nextQuestion | prevQuestion | showResults."

  ]
